import{_ as o,o as t,c as i,ae as a}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Basic Link Configuration","description":"","frontmatter":{"title":"Basic Link Configuration","slug":"basic-link-configuration"},"headers":[],"relativePath":"account-hub/basic-link-configuration.md","filePath":"account-hub/basic-link-configuration.md"}'),n={name:"account-hub/basic-link-configuration.md"};function r(s,e,l,d,c,p){return t(),i("div",null,[...e[0]||(e[0]=[a('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This article will help you configure link behavior for redirects and link domains.</p><p>It covers various settings such as default link behavior for different operating systems (Android, iOS), social media preview customization, and link domain selection.</p><p>It also explains advanced settings like URI scheme deep link mode, redirect allowlist, and UTM tag usage for analytics. Additionally, it discusses desktop app default link behavior, advanced mobile redirects, and provides a table mapping UTM parameters to Branch parameters.</p><h2 id="_1-default-link-behavior" tabindex="-1">1. Default link behavior <a class="header-anchor" href="#_1-default-link-behavior" aria-label="Permalink to &quot;1. Default link behavior&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Caution</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>This is a required setting.</p></div></div></div><p>:::</p><p>:::</p><p>In the left-side navigation of the Branch Dashboard, find the <a href="https://branch.dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer"><strong>App Settings</strong></a> page under <strong>Configure</strong>. Find the <strong>General</strong> tab, and in the the <strong>Required Redirects</strong> section, enter in your fallback URL for mobile devices that do not have a specified redirect.</p><h2 id="_2-android-default-link-behavior" tabindex="-1">2. Android default link behavior <a class="header-anchor" href="#_2-android-default-link-behavior" aria-label="Permalink to &quot;2. Android default link behavior&quot;">​</a></h2><p>This is a required setting.</p><p>Complete the following steps to configure the default behavior for your deep links:</p><ol><li>In the Branch Dashboard, navigate to <a href="https://branch.dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer"><strong>App Settings</strong></a> → <strong>General</strong> tab → <strong>Required Redirects</strong> section → <strong>Android Redirects</strong>.</li><li>Use the settings in this section to control the default behavior of your deep links on Android.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>The Play Store is for published apps. If your app cannot be located or is a local/dev build, please use the Custom URL option.</p></div><h3 id="generate-sha256-cert-fingerprint" tabindex="-1">Generate SHA256 cert fingerprint <a class="header-anchor" href="#generate-sha256-cert-fingerprint" aria-label="Permalink to &quot;Generate SHA256 cert fingerprint&quot;">​</a></h3><p>If you choose to <strong>Enable App Links</strong> you will need to generate a SHA256 Cert Fingerprint. Use one of the following methods to do this:</p><h4 id="keystore-file-method" tabindex="-1"><strong>KeyStore file method</strong> <a class="header-anchor" href="#keystore-file-method" aria-label="Permalink to &quot;**KeyStore file method**&quot;">​</a></h4><ol><li>Navigate to your <code>keystore file</code> (used to build the debug and production version of your APK file before it gets deployed).</li><li>Run <code>keytool -list -v -keystore my-release-key.keystore</code> to generate a fingerprint.<br> * Example fingerprint:<br><code>AA:C9:D9:A5:E9:76:3E:51:1B:FB:35:00:06:9B:56:AC:FB:A6:28: CE:F3:D6:65:38:18:E3:9C:63:94:FB:D2:C1</code> to add to your Branch Dashboard.</li></ol><h4 id="android-studio-method" tabindex="-1"><strong>Android Studio method</strong> <a class="header-anchor" href="#android-studio-method" aria-label="Permalink to &quot;**Android Studio method**&quot;">​</a></h4><ol><li>In Android Studio, open the Gradle options from the top-right corner of the page by selecting the elephant icon.</li><li>Select the terminal icon. It will say “Execute Gradle Task” when you hover over it.</li><li>Enter <code>--signingReport</code> and press Enter/Return.</li><li>Select the cat icon to open logcat. Copy the SHA256 Cert Fingerprint from logcat at the bottom of Android Studio.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>To host an <code>assetlinks.json</code> file that includes <strong>multiple package names</strong> for your development environment, please <a href="https://help.branch.io/v1/docs/submit-a-ticket" target="_blank" rel="noreferrer">submit a ticket</a> with the complete <code>digital assetlink.json</code> file.</p></div><h2 id="_3-ios-default-link-behavior" tabindex="-1">3. iOS default link behavior <a class="header-anchor" href="#_3-ios-default-link-behavior" aria-label="Permalink to &quot;3. iOS default link behavior&quot;">​</a></h2><p>This is a required setting.</p><p>Use these settings to control the default behavior of your deep links on iOS.</p><ol><li><p>In the Branch Dashboard, navigate to <a href="https://branch.dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer"><strong>App Settings</strong></a> → <strong>General</strong> tab → <strong>Required Redirects</strong> section → <strong>iOS Redirects</strong>.</p></li><li><p>If you choose to <strong>Enable Universal Links</strong>, you will need to enter your <strong>Apple App Prefix</strong> which can be found within the Apple Developer Portal for your app.</p></li><li><p>To enable deferred deep linking via <a href="https://help.branch.io/docs/nativelink-deferred-deep-linking#integration-guide" target="_blank" rel="noreferrer">NativeLink</a>™, you can click the <strong>Enable NativeLink™</strong> checkbox. Doing so means your users will be presented with a <a href="./deepviews-index.html">Deepview</a> that lets them continue their experience in an app, even if they don’t have it installed.</p><ol><li>Make sure to choose the appropriate audience in the <strong>Audience Rule</strong> dropdown.</li><li>Please ensure your iOS URI Scheme and Universal Links are properly configured.</li><li>Once enabled, follow the instructions in our <a href="./ios-advanced-features.html#nativelink-deferred-deep-linking">developer documentation</a> to use NativeLink™.</li></ol></li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>To host an Apple App Site Association (AASA) file that includes multiple App Prefixes (Team IDs) for your development environment, please <a href="https://help.branch.io/v1/docs/submit-a-ticket" target="_blank" rel="noreferrer">submit a ticket</a> with your finalized AASA file.</p></div><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>For any user running on an iOS version below 12.3, a popup first appears prompting the user to open in the App Store when being redirected to the app store. The user must click <strong>OK</strong> to be fully routed to the App Store to download your app. This popup cannot be removed from the user flow as it&#39;s inherent to iOS.</p></div><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Branch currently does <strong>not</strong> support using the same iOS App Store ID across multiple Branch apps.This limitation exists because Branch’s SKAN implementation requires a 1:1 mapping between each iOS App Store ID and Branch App ID. <strong>Exception</strong>: Test apps may use the same iOS App Store ID as production apps.</p></div><h2 id="_4-social-media-preview" tabindex="-1">4. Social media preview <a class="header-anchor" href="#_4-social-media-preview" aria-label="Permalink to &quot;4. Social media preview&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Note</p><p>You can change the social media preview for individual Short Links when you create them.</p></div><ol><li>In the Branch Dashboard, navigate to <a href="https://branch.dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer"><strong>App Settings</strong></a> → <strong>General</strong> tab → <strong>Social Media Preview</strong> section.</li><li>Fill in the following fields to customize how the link to your install page will look when shared or re-shared on social media:<br> a. Link Title<br> b. Description<br> c. Thumbnail Image</li></ol><h2 id="_5-link-domain" tabindex="-1">5. Link domain <a class="header-anchor" href="#_5-link-domain" aria-label="Permalink to &quot;5. Link domain&quot;">​</a></h2><p>To see your app’s default link domain and alternate link domain, navigate to the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">General tab</a> of the App Settingspage of the Branch Dashboard.</p><p>When you first create your account, you will be assigned a unique domain for all of your Branch Links.</p><h3 id="change-link-domain" tabindex="-1">Change link domain <a class="header-anchor" href="#change-link-domain" aria-label="Permalink to &quot;Change link domain&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Before changing your Branch link domain, it is important to understand all behavior changes that occur when you do so. This will help ensure you do not run into any unwanted experiences for your users clicking your Branch Links.</p></div><table tabindex="0"><thead><tr><th>Change</th><th>Example</th><th>Behavior</th></tr></thead><tbody><tr><td><code>app.link</code> to <code>app.link</code></td><td><code>abcdef.app.link</code> → <code>mycompany.app.link</code></td><td>- Your old <code>app.link</code> URLs will redirect to the <strong>LINK NOT FOUND</strong> page. - Your old <code>app.link</code> URLs will fail to open your mobile app. - Your new <code>app.link</code> URLs will not open your app until you update your code to utilize the new link domain (<a href="./ios-basic-integration.html">iOS</a> / <a href="./android-basic-integration.html">Android</a>). - If you are already using your original/old <code>app.link</code> URLs in the wild and need them to keep working, it is recommended to explore <a href="./advanced-settings-configuration.html#using-your-own-domain">Using Your Own Domain</a> instead.</td></tr><tr><td><code>app.link</code> to Custom Domain</td><td><code>mycompany.app.link</code> → <code>app.mycompany.com</code></td><td>- Your old <code>app.link</code> URLs will still work. - Your new Custom Domain URLs will not open your app until you update your code to utilize the new link domain (<a href="./ios-basic-integration.html">iOS</a> / <a href="./android-basic-integration.html">Android</a>). - <a href="./creating-a-deep-link.html">Creating Long Links Details</a></td></tr><tr><td>Custom Domain to Custom Domain</td><td><code>app.mycompany.com</code> → <code>mycompany.app</code></td><td>- Your old Custom Domain URLs will fail to deep link. - Your new Custom Domain URLs will not open your app until you update your code to utilize the new link domain (<a href="./ios-basic-integration.html">iOS</a> / <a href="./android-basic-integration.html">Android</a>).</td></tr><tr><td>Legacy <code>bnc.lt</code> to <code>app.link</code> or Custom Domain</td><td><code>bnc.lt</code> → <code>mycompany.app.link</code> <code>bnc.lt/branch</code> → <code>app.mycompany.com</code></td><td>- Both your <code>bnc.lt</code> and <code>app.link</code>/Custom Domain deep links will work. - Your new <code>app.link</code>/Custom Domain URLs will not open your app until you update your code to utilize the new link domain (<a href="./ios-basic-integration.html">iOS</a> / <a href="./android-basic-integration.html">Android</a>).</td></tr></tbody></table><h3 id="change-app-link-subdomain" tabindex="-1">Change app.link subdomain <a class="header-anchor" href="#change-app-link-subdomain" aria-label="Permalink to &quot;Change app.link subdomain&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Changing your <code>app.link</code> subdomain can only be performed <strong>once</strong> for your Branch app.</p></div><p>You have the ability to change your <code>app.link</code> subdomain for your Branch Links to better match your brand. It is recommended to set your <code>app.link</code> subdomain to be the name of your app, in case you have multiple mobile apps under your brand.</p><p>To customize your <code>app.link</code> subdomain:</p><ol><li>Review and understand <a href="./advanced-settings-configuration.html#change-link-domain">what it means to change your domain</a>.</li><li>Click the <strong>Change My</strong> <code>app.link</code> <strong>Subdomain</strong> button.</li><li>Input your new preferred <code>app.link</code> subdomain. You can only set it to a subdomain that is not already taken by another Branch app.</li><li>Update your mobile app to use the new <code>app.link</code> subdomain.</li></ol><h3 id="use-your-own-domain" tabindex="-1">Use your own domain <a class="header-anchor" href="#use-your-own-domain" aria-label="Permalink to &quot;Use your own domain&quot;">​</a></h3><p>Depending on your <a href="http://branch.io/pricing" target="_blank" rel="noreferrer">package</a>, you may have the ability to use your own custom domain to be used for your Branch Links. Branch supports the use of a custom subdomain or a custom root domain for you to be able to set your Branch Links closer to your branding preferences.</p><h4 id="considerations" tabindex="-1">Considerations <a class="header-anchor" href="#considerations" aria-label="Permalink to &quot;Considerations&quot;">​</a></h4><ul><li>Whenever you change the NS or CNAME records of your domain, you are making Branch the authoritative registrar of your domain. This will grant Branch control of your domain and you will lose access to that custom subdomain or custom root domain. The web page will become blank, and the control of the domain will change to Branch</li><li>Branch will use the domain to route all deep linked traffic.</li><li>Branch will host your AASA file and SSL certifications.</li><li>If you have content on your custom root domain, Branch recommends using an unused custom subdomain.</li></ul><table tabindex="0"><thead><tr><th>Limitation</th><th>Details</th></tr></thead><tbody><tr><td>Android App Links &amp; Web Limitations</td><td>Android App Links together on custom subdomains and custom root domains currently do not support Branch&#39;s web-only link functionality. Using the <code>$web_only</code> parameter on Branch Links that only open the web even if the app is installed. Because of this limitation, <strong>Android App Links will force the app to open even when using the</strong> <code>$web_only</code> <strong>parameter</strong>. <strong>Note</strong>: This limitation only applies to Engagement. This does not apply to Activation.</td></tr><tr><td>Web</td><td>If you have Activation, you can use a custom domain for web links. For other packages, <strong>you must use the assigned default link alias</strong>.</td></tr></tbody></table><h4 id="implementation-options-for-activation" tabindex="-1">Implementation options for Activation <a class="header-anchor" href="#implementation-options-for-activation" aria-label="Permalink to &quot;Implementation options for Activation&quot;">​</a></h4><p>These options only apply if you have Branch Activation and have the ability to add multiple custom domains.</p><p><strong>Option 1: Single domain for web and app</strong></p><p>Use this approach to have a single custom domain to handle links that point to both web pages and in-app locations.</p><ul><li><p><strong>How it works</strong>: This configuration relies on Universal Links (iOS) and Android App Links to prioritize opening the app. If a user has your app and clicks a web link, the link will open in an in-app webview.</p></li><li><p><strong>Requirements</strong>: Your apps must have the <em>at least</em> the following SDK versions to support this option:</p><ul><li>iOS SDK ≥ 3.12.0</li><li>Android SDK ≥ 5.18.0</li></ul></li><li><p><strong>Pro:</strong> You can change a link&#39;s destination between a web page and an app view at any time without needing to generate a new link or update a QR code.</p></li><li><p><strong>Con</strong>: Requires having updated SDK versions to ensure a consistent user experience for all link types.</p></li></ul><p><strong>Option 2: Separate domains</strong></p><p>Use this approach to have separate dedicated domains for web links and app links, ensuring a clear separation of user experiences.</p><ul><li><p><strong>How it works</strong>: You configure at least two domains:</p><ul><li><strong>Web domain</strong>: A domain designated for web links. Links using this domain will never open the app and will always direct users to their mobile browser.</li><li><strong>App domain</strong>: A separate domain (for example, your default app.link domain or another custom domain) used exclusively for deep linking.</li></ul></li><li><p><strong>Requirements</strong>: No SDK update is required to implement this strategy, as the web domain does not interact with the SDK. However, you must integrate the Branch SDK if you want to deep link to locations in your app with app links.</p></li><li><p><strong>Pro</strong>: This method provides a predictable user experience by avoiding the in-app webview and does not require an SDK update to create web links.</p></li><li><p><strong>Con</strong>: A link&#39;s behavior is fixed to its domain. To switch a link&#39;s destination from a web page to an app view (or vice-versa), you must create an entirely new link using the appropriate domain.</p></li></ul><h3 id="use-a-custom-subdomain" tabindex="-1">Use a custom subdomain <a class="header-anchor" href="#use-a-custom-subdomain" aria-label="Permalink to &quot;Use a custom subdomain&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Do not use your main website domain for your Branch Links.</p></div><p>If your enterprise is highly restrictive of the domains that you utilize and wants to ensure that your Branch domain matches the rest of your relevant subdomains, you can utilize a custom subdomain, for example <code>link.yourbrand.com</code> .</p><p>Before you set up a custom subdomain:</p><ol><li>Review and understand the table outlining <a href="./basic-link-configuration.html#change-link-domain">what it means to change your link domain</a>.</li><li>Update the DNS CNAME of your custom subdomain to point to <code>custom.bnc.lt</code> . If using AWS Route 53, do this in the Registered Domain tab, not in Hosted Zones.</li><li>Use the <a href="https://www.entrust.com/resources/certificate-solutions/tools/caa-lookup" target="_blank" rel="noreferrer">CAA Lookup Tool</a> to see if you need to update your <code>CAA</code> records of your custom subdomain to include <code>letsencrypt.org</code>.</li></ol><p>To set up your custom subdomain:</p><ol><li>In the Branch Dashboard, select <strong>App Settings</strong> from the navigation menu.</li><li>Scroll down to the <strong>Link Domain</strong> section.</li><li>Select <strong>Use My Own Domain</strong>.</li><li>Input your custom subdomain (without the <code>www</code> ) and select <strong>Confirm</strong>.</li><li>Update your mobile app to use the new custom subdomain.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>For instructions about adding custom domains in the new Branch experience, read our <a href="./link-appearance-new.html">Link Appearance (New)</a> article.</p></div></div><p>:::</p><h4 id="use-a-custom-root-domain" tabindex="-1">Use a custom root domain <a class="header-anchor" href="#use-a-custom-root-domain" aria-label="Permalink to &quot;Use a custom root domain&quot;">​</a></h4><p>If you need to establish an entirely separate domain for your Branch domain, you can use a custom root domain, for example <code>yourbrand-link.com</code>. This is only recommended if your company is not open to <code>app.link</code> or a custom subdomain option.</p><p>Before you set up a custom root domain:</p><ol><li><p>Review and understand <a href="./advanced-settings-configuration.html#change-link-domain">what it means to change your link domain</a>.</p></li><li><p>Update the <code>NS</code> records of your custom root domain using the following nameservers:</p><ul><li><code>ns-1581.awsdns-05.co.uk</code></li><li><code>ns-234.awsdns-29.com</code></li><li><code>ns-1059.awsdns-04.org</code></li><li><code>ns-843.awsdns-41.net</code></li></ul></li><li><p>Use the <a href="https://www.entrust.com/resources/certificate-solutions/tools/caa-lookup" target="_blank" rel="noreferrer">CAA Lookup Tool</a> to see if you need to update your <code>CAA</code> records of your custom subdomain to include <code>letsencrypt.org</code>.</p></li></ol><p>To set up your custom root domain:</p><ol><li>In the Branch Dashboard, select <strong>App Settings</strong> from the navigation menu.</li><li>Scroll down to the <strong>Link Domain</strong> section.</li><li>Select <strong>Use My Own Domain</strong>.</li><li>Input your custom root domain (without the <code>www</code> ) and select <strong>Confirm</strong>.</li><li>Update your mobile app to use the new custom subdomain.</li></ol><p>For instructions about adding custom domains in the new Branch experience, read our <a href="./link-appearance-new.html">Link Appearance (New)</a> article.</p><h4 id="add-additional-custom-domains" tabindex="-1">Add additional custom domains <a class="header-anchor" href="#add-additional-custom-domains" aria-label="Permalink to &quot;Add additional custom domains&quot;">​</a></h4><p>You can add additional multiple custom domains for your Branch links. This can be useful for having separate domains for web or app links, using different domains for different channels, and more.</p><p>Follow the directions in the “Use a custom subdomain” or “Use a custom root domain” sections above to add additional domains.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>The ability to add multiple custom domains is only available in <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">some Branch packages</a>.</p></div><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><p>For steps on how to configure the other settings in the <strong>General</strong> tab, visit our <a href="./advanced-link-configuration.html">Advanced Settings</a> and <a href="./additional-link-configuration.html">Additional Setting</a>s guides.</p>',77)])])}const m=o(n,[["render",r]]);export{h as __pageData,m as default};
